INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-04810', 'social-worker', 'social-worker-moex-108-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '承上題，作者對於嗜食檳榔所持態度，下列敘述何者錯誤？', '["作者與醫師討論，認為食檳榔能降氣，也能耗氣", "作者探詢酷食者的服食原因，他們認為服食檳榔可以「辟瘴，下氣，消食」", "「路上行人口似羊」描寫咀嚼檳榔蔞葉之狀，作者對此服食風習持肯定態度", "作者與醫師均謂，服食檳榔未必真能降瘴氣，而且瘴氣致病，其理非一，非盡不 食檳榔故也"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "3f86db5a23ec", "answer_pdf_sha1": "60dbb347d2af", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04811', 'social-worker', 'social-worker-moex-108-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '宋人有酤酒者，升概甚平，遇客甚謹，為酒甚美，縣幟甚高，然而不售，酒酸。怪 其故，問其所知閭長者楊倩。倩曰：「汝狗猛耶？」曰：「狗猛則酒何故而不售？」 曰：「人畏焉。或令孺子懷錢挈壺甕而往酤，而狗迓而齕之，此酒所以酸而不售也。」 夫國亦有狗。有道之士懷其術而欲以明萬乘之主，大臣為猛狗，迎而齕之，此人主 之所以蔽脅，而有道之士所以不用也。（《韓非子．外儲說右上》） 根據上文，下列選項何者正確？', '["酒酸是因為縣幟甚高的緣故，不必怪罪於狗", "本文形象地表達奸臣當道，妒賢忌能，對社稷危害甚深", "大臣比喻為猛狗，意味大臣衷心為朝廷服務，積極為國君分憂", "有道之士之所以不受重用，正是因為人主沉溺於聲色犬馬而荒廢朝政"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "3f86db5a23ec", "answer_pdf_sha1": "60dbb347d2af", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04812', 'social-worker', 'social-worker-moex-108-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '某翁，家藏一宋代瓷瓶，精美絕倫，置內室架上，秘不示人。一日，自外入，見瓶 半懸架外，岌岌乎欲墜，遂勃然。集其家人，欲究咎責。媼怨子，子尤婦，婦又歸 咎於僕，僕指天劃地，力辯其誣。舉室嘩然，嘵嘵未已，日偏西而不覺也。忽風動 帘帷，帷拂危瓶，瓶墜地粉碎矣。一室擾攘，戛然而止。 下列敘述切合上文旨意的選項是：', '["言行不一，難明真象", "眼見為憑，多說無益", "推諉究責，無益於事", "信耳疑目，古今所患"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "3f86db5a23ec", "answer_pdf_sha1": "60dbb347d2af", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04813', 'social-worker', 'social-worker-moex-108-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「在如此急功近利的風尚裡，我有一次提到文學家心目中的成功；江山代有才人 出，各領風騷二百年！在旁邊的青年忽然插嘴說：『不必二百年，只領一天風騷， 我就滿足了！』這話讓我有一番警省，可以領風騷二百年的人物，必須真積力久， 內涵飽滿充實，而只求領一天風騷的，大概靠傳播媒體及商業流行的設計就可以達 到了，前者是『目窮千里』而長期凝成的精神實力，後者是花樣淺薄與隨時報銷的 心態假象，如果我們青年讓商業設計牽著鼻子，追求像槿花一般，在一日之間枯榮 的流行虛象，那就很可悲。」下列選項最接近本文旨趣的是：', '["生於憂患，死於安樂", "君子坦蕩蕩，小人長戚戚", "無望其速成，無誘於勢利", "不義而富且貴，於我如浮雲"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "3f86db5a23ec", "answer_pdf_sha1": "60dbb347d2af", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04814', 'social-worker', 'social-worker-moex-108-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「當牌局進展激烈的當兒，尹雪艷便換上輕裝，周旋在幾個牌桌之間，踏著她那風 一般的步子，輕盈盈的來回巡視著，像個通身銀白的女祭司，替那些作戰的人們祈 禱和祭祀。」下列選項最適合描述尹雪艷的是：', '["冰清玉潔", "沉魚落雁", "蝴蝶穿花", "膚如凝脂"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "3f86db5a23ec", "answer_pdf_sha1": "60dbb347d2af", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04815', 'social-worker', 'social-worker-moex-108-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '真正能體會音樂之美的人，大概都能清楚「在語言停住的地方，開始了音樂」這句 白話有著何等高遠的道理。面對氣氛無限的音樂，有限的我常在它絕美得無法形容 的聲音裡矛盾、哀傷、甜蜜、泫然。那風急天高的巴哈管風琴，那千山萬壑的貝多 芬交響曲，多麼令人狂喜、振奮，但為何在聽完之後總有一股難言的落寞。音樂境 界是蒼茫永恆的，而我們對它的傾心又是無終無始，無端無由的，這種美的認同， 已完全超乎人類的樣式，因而難免落寞，落寞，但卻是幸福的、高逸的。道院吹笙， 松風裊裊；空門洗缽，花雨紛紛。落寞是音樂的一種獨特、神祕的美感，而且一與 之訂，千秋不移。此文中對於音樂的描述，下列選項，何者正確？', '["音樂的境界，往往是曲高和寡，知音難覓", "欲尋音樂之美，必須潛心靜氣，深思冥想", "自然界的天籟，人類的音樂形式難以企及", "音樂最美之處，在急管繁絃，萬籟俱寂時"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "3f86db5a23ec", "answer_pdf_sha1": "60dbb347d2af", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04816', 'social-worker', 'social-worker-moex-108-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '元代民歌云：「赤日炎炎似火燒，野田禾稻半枯焦。農夫心內如湯煮，公子王孫把 扇搖。」歌詞中之意涵與下列何者最相近？', '["蠻煙不雨似雲濃，白日陰陰慘澹中。炎氣薰人冬亦暖，不知何地候春風", "桑條無葉土生煙，簫管迎龍水廟前。朱門幾處看歌舞，猶恐春陰咽管弦", "天旱久不雨，四郊多狂風。蕭蕭班馬鳴，落日大野中。君子守宮廷，至樂聖所同。 喟予不逢辰，足跡道里重", "湘竹披煙，剡藤裁雪。斂舒蹙就棕櫚摺。動搖一握展開時，半彎恍訝瑤空月。赤 日低焚，火雲高結。人間何處逃炎熱。便將入手不停揮，涼風滿面真清絕"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "3f86db5a23ec", "answer_pdf_sha1": "60dbb347d2af", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04817', 'social-worker', 'social-worker-moex-108-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '一介之士，必有密友；密友不必定是刎頸之交。大率雖千百里之遙，皆可相信，而 不為浮言所動；聞有謗之者，即多方為之辯析而後已。事之宜行宜止者，代為籌畫 決斷；或事當利害關頭，有所需而後濟者，即不必與聞，亦不慮其負我與否，竟為 力承其事。此皆所謂密友也。（張潮《幽夢影》） 下列敘述，最符合文中所說「密友」特質的是：', '["言行正直，性格敦厚", "捨命為友，在所不惜", "互相信任，義無反顧", "知識淵博，閱歷豐富"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "3f86db5a23ec", "answer_pdf_sha1": "60dbb347d2af", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04818', 'social-worker', 'social-worker-moex-108-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '同幫者無論舊交新識，得素所敬重或素所親厚之人為佳。何也？人之性情各有不 同，人之學問亦各有不同，則其見解議論，安能如一？惟所敬重者，常有畏心，不 敢相忤；所親厚者，常有愛心，不忍相嫌。即有異同，而斷無芥蒂。此真可與遊者 也。（林伯桐《公車見聞錄》） 依據上文，下列選項的敘述何者不符合文意？', '["北上赴考路途遙遠，因此必須約幫同行，一如今日之自助旅遊之結伴", "畏愛之心，自有人與人的距離象徵，雖疏密有別，當有相處合宜之道", "出門在外，諸事不便，彼此遷就的事情頗多，因此必須慎選結伴之人", "選擇所敬重者與所親厚之人，考量的是彼此能否肝膽相照，不生嫌隙"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "3f86db5a23ec", "answer_pdf_sha1": "60dbb347d2af", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04819', 'social-worker', 'social-worker-moex-108-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「過去我們經常以為人性是統一的。然而，現代的美學思想已經開始認為，人是許 多分裂狀態的不完整的統一，他可能是兩極的。法國作家卡繆寫《異鄉人》用的是 巴黎發生的兇殺案件，為了讓這個開槍打死阿拉伯人的法國青年變成十惡不赦的罪 犯，檢察官開始搜集他生命的罪狀，包括他在母親死時沒有掉眼淚，隔日還跟女友 出去玩並發生關係。注意，這是先有結論，才開始搜集證據；所以存在主義說，存 在先於本質，不應該先對人的本質下定論之後，再去搜羅存在的狀態，存在的本身 應該是觀察的起點，即使荒謬，都應該去觀察，而不能將其排斥除外。」 下列選項，何者最符合文意？', '["我們對人的觀察常常習於未審先判", "善人必有善舉，善舉也必出於善人", "任何兇殺案件必然關乎荒謬的存在", "人的本質捉摸不定，無法正確觀察"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "3f86db5a23ec", "answer_pdf_sha1": "60dbb347d2af", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
